INSERT INTO "public"."courses" ("id", "title", "description", "teacher_id", "category", "level", "is_active", "created_at", "updated_at", "video_url", "price", "duration", "thumbnail_url", "is_published", "is_visible", "image_url", "duration_months", "hide_price") VALUES ('6d92c6be-177a-41ad-a555-ae2f8f4b1092', 'Descubrir la matemática 4', 'Descubrir la Matemática 4 es el tercer libro de la serie Descubrir la Matemática, un programa dirigido a docentes de niños de 8 a 12 años, que tiene como finalidad aprender a pensar la matemática de una manera fácil, divertida, novedosa e inspiradora. Es recomendable para niños de 7 a 8 años,.

La didáctica por procesos, basada en la didáctica de Federici, es el mecanismo por el cual el estudiante aprende de una manera personalizada, sin que esto implique retraso, por el contrario, aunque inicialmente puede parecer que no hay avance, lo que se está garantizando es se consoliden los procesos ya que se retoman en cada período u año escolar. Esto hace que "Descubrir la matemática" sea un programa único donde la matemática deja de ser la materia frustrante y accesible solo para unos pocos, donde el niño aprende de una manera fácil y divertida, y fortalece su autoestima, autonomía y creatividad.', null, 'mathematics', null, 'true', '2026-03-10 02:44:21.385+00', '2026-03-12 05:22:22.777+00', 'https://www.youtube.com/embed/yIr_1CasXkM', '1.3', '1', null, 'false', 'true', '', '5', 'false'), ('be4e5289-b793-4f12-a27e-9ea2a307f10d', 'Descubrir la matematica 2', 'Descubrir la matemática 2 es el primer nivel de Descubrir la Matemática, un programa para aprender la matemática. El curso está dirigido a docentes de niños de 2 a 3 años para', null, 'mathematics', null, 'true', '2026-03-09 22:09:13.231+00', '2026-03-09 23:59:23.624+00', '', '0', '10', null, 'false', 'true', '', '1', 'true'), ('c2c0caae-45e4-4b1f-a4ed-cc2deefce166', 'Matemáticas Básicas', 'Aprende sumas, restas y más', null, 'matematicas', 'principiante', 'true', '2026-03-05 14:45:10.160018+00', '2026-03-05 15:45:00.655+00', null, '5000', '1', null, 'false', 'true', null, '1', 'false'), ('d5d4f012-7438-462a-aaf7-405b0e430cc9', 'Descubrir la matemática 4', 'Descubrir la Matemática 4 es el tercer libro de la serie Descubrir la Matemática un programa dirigido al docente (padre y madre de familia, profesor de institución educativa formal e informal) de niños de 7 a 8 años. Aunque es recomendable que inicien con el primer libro, Descubrir la Matemática 2, ya que es fundamental recorrer paso a paso el proceso de desarrollo del pensamiento lógico matemático.
La intención de este programa es consolidar las bases del pensamiento que le permitan construir el significado del concepto, más allá de manipular números en forma mecánica sin significado. También se pretende enviar un mensaje a aquellos padres e instituciones que pretenden “forzar” el aprendizaje enseñando símbolos o números sin significado antes de los cuatro años.
La didáctica por procesos, basada en la didáctica de Federici, es el mecanismo por el cual el estudiante aprende de una manera personalizada, sin que esto implique retraso, por el contrario, aunque inicialmente puede parecer que no hay avance, lo que se está garantizando es se consoliden los procesos ya que se retoman en cada período u año escolar. Esto hace que "Descubrir la matemática" sea un programa único donde la matemática deja de ser la materia frustrante y accesible solo para unos pocos, donde el niño aprende de una manera fácil y divertida, y fortalece su autoestima, autonomía y creatividad.', null, 'mathematics', null, 'true', '2026-03-13 22:05:20.527+00', '2026-03-13 22:05:20.527+00', 'https://www.youtube.com/embed/yIr_1CasXkM', '0', '1', null, 'false', 'true', '', '1', 'true'), ('d6c7e331-de48-4b88-a4bc-9268cec705c0', 'Álgebra Divertida', 'Ecuaciones y variables de forma fácil', null, 'algebra', 'intermedio', 'true', '2026-03-05 14:45:10.160018+00', '2026-03-05 14:45:10.160018+00', null, '0', '0', null, 'false', 'true', null, '1', 'false'), ('f38a2a4f-97f9-4987-bf79-3008f8942278', 'mate 2', 'dasfgsdagfasdf', null, 'education', null, 'true', '2026-03-05 15:43:14.505+00', '2026-03-05 15:50:16.996+00', 'https://www.youtube.com/embed/yIr_1CasXkM', '150000', '2', null, 'false', 'true', null, '1', 'false'), ('fce704a6-394c-481b-9dc5-8fef3a065eec', 'descubrir matematica 3', 'Descubrir la matemática 3 es el segundo libro de la serie Descubrir la Matemática, un programa para aprender la matemática novedoso, divertido, fácil e inspirador. Con algunas excepciones, podrán iniciar niños de 7 a 8 años con en este Nivel. Lo más recomendado es iniciar con el Nivel 1.', null, 'mathematics', null, 'true', '2026-03-09 23:38:46.151+00', '2026-03-09 23:38:46.151+00', '', '1300000', '1', null, 'false', 'true', '', '10', 'true');